import type { LayoutViewStore } from './types';

import {
  getGlobalThemeContextScript,
  getStyles as getGlobalThemeStyles,
} from '@global-theme/context/server';

import { NoopWrapper } from '../react/NoopWrapper';
import { getFontResources } from './fonts';

export async function createLayoutViewStore(
  cdn: string,
): Promise<LayoutViewStore> {
  const [globalThemeContextScript, globalThemeStyles, fontsResources] =
    await Promise.all([
      getGlobalThemeContextScript(),
      getGlobalThemeStyles(),
      getFontResources(cdn),
    ]);

  return {
    lang: '',
    headSlots: {
      title: NoopWrapper,
      links: fontsResources.links,
      meta: [],
      styles: [fontsResources.style, globalThemeStyles],
      scripts: [globalThemeContextScript],
    },
    bodySlots: {
      start: [],
      main: NoopWrapper,
      end: [],
      scripts: [],
    },
  };
}
